import React from 'react';
import Sidebar from '../components/Sidebar';
import ChatWindow from '../components/ChatWindow';
import './ChatPage.css';

const ChatPage = () => {
  return (
    <div className="chat-page">
      <div className="chat-body">
        <Sidebar />
        <ChatWindow />
      </div>
    </div>
  );
};

export default ChatPage;
